import { useMemo, useState } from "react";
import SEOHead from "@/components/SEOHead";
import AdPlaceholder from "@/components/AdPlaceholder";
import RelatedTools from "@/components/RelatedTools";
import ShareButton from "@/components/ShareButton";
import FAQItem from "@/components/FAQItem";
import { formatCurrencyValue, useCurrencyVersion } from "@/lib/currency";

const FAQS = [
  { q: "What is future value?", a: "Future value is the amount money may grow to after earning interest or returns over time." },
  { q: "How do you calculate future value?", a: "Compound the present value by multiplying it by (1 + rate) for each period, then add the future value of any recurring payments." },
  { q: "What is the future value formula?", a: "For a lump sum, FV = PV  x  (1 + r)^n. With payments, add the future value of the annuity stream." },
  { q: "How does compounding frequency affect future value?", a: "More frequent compounding can increase future value because interest is added to the balance more often." },
  { q: "What is the future value of an annuity?", a: "It is the future value of a series of equal payments, compounded to the end of the investment period." },
];

const money = (v: number, d = 2) => formatCurrencyValue(Number.isFinite(v) ? v : 0, { maximumFractionDigits: d });
const inputClass = "w-full px-3 py-2 rounded-xl border border-input bg-background text-foreground text-lg font-bold focus:outline-none focus:ring-2 focus:ring-primary/40 transition-all";
const fv = (pv: number, rate: number, years: number, freq: number, pmt = 0) => {
  const r = rate / 100 / freq;
  const n = years * freq;
  const lump = pv * Math.pow(1 + r, n);
  const annuity = r === 0 ? pmt * n : pmt * ((Math.pow(1 + r, n) - 1) / r);
  return lump + annuity;
};

export default function FutureValueCalculator() {
  useCurrencyVersion();
  const [presentValue, setPresentValue] = useState(10000);
  const [rate, setRate] = useState(7);
  const [years, setYears] = useState(10);
  const [frequency, setFrequency] = useState(12);
  const [payment, setPayment] = useState(250);
  const result = useMemo(() => {
    const value = fv(presentValue, rate, years, frequency, payment);
    return { value, interest: value - presentValue - payment * years * frequency };
  }, [presentValue, rate, years, frequency, payment]);
  const rows = Array.from({ length: Math.min(30, Math.max(1, years)) }, (_, i) => ({ year: i + 1, value: fv(presentValue, rate, i + 1, frequency, payment) }));
  const rates = [3, 5, 7, 10, 12];
  const terms = [5, 10, 20, 30];

  return (
    <>
      <SEOHead title="Free Future Value Calculator Online - Calculate FV of Any Investment Instantly | CalcHive" description="Free online future value calculator. Calculate the future value of any present amount or annuity at any interest rate and time period instantly. 100% free, no signup required." canonical="/future-value-calculator" keywords="free future value calculator, FV calculator free online, calculate future value free, future value of investment calculator free, compound growth calculator free" category="Financial Calculators" breadcrumbName="Free Future Value Calculator Online" schemaType="WebApplication" schemaApplicationCategory="CalculatorApplication" faqs={FAQS} />
      <main className="max-w-3xl mx-auto px-4 sm:px-6 py-10"><div className="mb-8"><span className="text-xs font-semibold uppercase tracking-widest text-sky-600 dark:text-sky-400 bg-sky-50 dark:bg-sky-950/50 px-3 py-1 rounded-full mb-4 inline-block">Financial</span><h1 className="text-3xl sm:text-4xl font-extrabold text-foreground tracking-tight mb-3">Free Future Value Calculator Online</h1><p className="text-muted-foreground leading-relaxed">Calculate future value from a starting amount, recurring payments, rate, and time.</p></div><AdPlaceholder size="banner" className="mb-8" />
        <section className="bg-card border border-border rounded-2xl p-6 sm:p-8 shadow-md mb-8"><div className="grid grid-cols-1 sm:grid-cols-2 gap-4 mb-8"><div><label className="text-sm font-semibold text-foreground block mb-2">Present value</label><input type="number" value={presentValue} onChange={(e) => setPresentValue(Number(e.target.value))} className={inputClass} /></div><div><label className="text-sm font-semibold text-foreground block mb-2">Interest rate (%)</label><input type="number" value={rate} onChange={(e) => setRate(Number(e.target.value))} className={inputClass} /></div><div><label className="text-sm font-semibold text-foreground block mb-2">Years</label><input type="number" value={years} onChange={(e) => setYears(Number(e.target.value))} className={inputClass} /></div><div><label className="text-sm font-semibold text-foreground block mb-2">Compounding frequency</label><select value={frequency} onChange={(e) => setFrequency(Number(e.target.value))} className={inputClass}><option value={1}>Annually</option><option value={4}>Quarterly</option><option value={12}>Monthly</option><option value={365}>Daily</option></select></div><div><label className="text-sm font-semibold text-foreground block mb-2">Payment per period</label><input type="number" value={payment} onChange={(e) => setPayment(Number(e.target.value))} className={inputClass} /></div></div><div className="bg-gradient-to-br from-sky-500 to-sky-700 rounded-2xl p-6 text-center shadow-lg"><p className="text-xs font-semibold uppercase tracking-widest text-white/70 mb-1">Future Value</p><p className="text-5xl sm:text-6xl font-black text-white">{money(result.value)}</p></div><div className="bg-accent/60 border border-border rounded-xl p-4 text-center mt-4"><p className="text-xs text-muted-foreground">Total interest earned</p><p className="text-lg font-extrabold text-foreground">{money(result.interest)}</p></div></section><ShareButton />
        <section className="mb-8 space-y-6"><h2 className="text-2xl font-bold text-foreground">How to Calculate Future Value of Any Investment for Free</h2><p className="text-muted-foreground leading-relaxed">Future value compounds the starting balance and recurring payments forward by the selected rate and compounding frequency.</p><h2 className="text-2xl font-bold text-foreground">How Interest Rate and Time Grow Your Money</h2><div className="overflow-x-auto"><table className="w-full text-sm border border-border rounded-xl overflow-hidden"><caption className="caption-top text-left font-bold text-foreground mb-3">Future Value of $10,000 at Different Rates and Periods</caption><thead className="bg-muted/60"><tr><th className="text-left py-3 px-3">Interest Rate</th>{terms.map((t) => <th key={t} className="text-left py-3 px-3">{t} Years</th>)}</tr></thead><tbody className="divide-y divide-border">{rates.map((r) => <tr key={r}><td className="py-2.5 px-3 font-semibold">{r}%</td>{terms.map((t) => <td key={t} className="py-2.5 px-3">{money(fv(10000, r, t, 1, 0), 0)}</td>)}</tr>)}</tbody></table></div><div className="overflow-x-auto"><table className="w-full text-sm border border-border rounded-xl overflow-hidden"><caption className="caption-top text-left font-bold text-foreground mb-3">Year by Year Growth</caption><thead className="bg-muted/60"><tr><th className="text-left py-3 px-3">Year</th><th className="text-left py-3 px-3">Future Value</th></tr></thead><tbody className="divide-y divide-border">{rows.slice(0, 10).map((r) => <tr key={r.year}><td className="py-2.5 px-3 font-semibold">{r.year}</td><td className="py-2.5 px-3">{money(r.value)}</td></tr>)}</tbody></table></div><h2 className="text-2xl font-bold text-foreground">Free FV and Compound Growth Calculator for Everyone</h2></section>
        <section className="mb-8"><h3 className="text-xl font-bold text-foreground mb-4">Frequently Asked Questions</h3><div className="space-y-3">{FAQS.map((faq) => <FAQItem key={faq.q} q={faq.q} a={faq.a} />)}</div></section><AdPlaceholder size="rectangle" className="mx-auto mb-8" /><RelatedTools exclude="/future-value-calculator" headingLevel="h3" /></main>
    </>
  );
}


